local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("dst", function(fn, notDstFn, ...)     local isDst = false     if not fn then         return isDst     end     if isDst then         fn(...)     elseif TD.isFn(notDstFn) then         notDstFn(...)     end     return isDst end) TD.createFn("ds", function(fn, notDsFn, ...)     local isDs = true     if not fn then         return isDs     end     if isDs then         fn(...)     elseif TD.isFn(notDsFn) then         notDsFn(...)     end     return isDs end) TD.createFn("dst_r", function(a, b)     if TD.dst() then         if TD.isFn(a) then             return a()         else             return a         end     else         if TD.isFn(b) then             return b()         else             return b         end     end end) TD.createFn("GetPlayer", function()     local player = nil     if TD.ThePlayer then         return TD.ThePlayer     end     if TD.dst() then         player = _G.ThePlayer     else         player = _G.GetPlayer()     end     if player then         TD.ThePlayer = player     end     return player end) TD.createFn("GetWorld", function()     if TD.dst() then         return _G.TheWorld     else         local world = _G.GetWorld()         world.ismastersim = true         return world     end end) TD.createFn("hideShip", function()     if TD.dst() then         return     end     local player = TD.GetPlayer()     if player.components.driver and player.components.driver.vehicle then         player.components.driver.vehicle:Hide()     end end) TD.createFn("showShip", function(timeout)     if TD.dst() then         return     end     local player = TD.GetPlayer()     TD.hideShip()     TD.removeTask(player, "td1madao_showShipTask")     if player and player.components.driver and player.components.driver.vehicle then         player.td1madao_showShipTask = TD.latter(player, timeout or 1, function()             TD.hideShip()         end)         player.components.driver.vehicle:Show()     end end) 